parameters.jsCode:
const base = $('Normalize Input').first().json;
const classifierRaw = $('Intake Classifier Agent').first().json;
const sentimentRaw = $('Sentiment Analyzer Agent').first().json;

let classifier = {};
let sentiment = {};

try {
  classifier = JSON.parse(classifierRaw.choices?.[0]?.message?.content || '{}');
} catch (error) {
  classifier = { category: 'general', urgency: 'medium', reason: 'classifier_parse_failed' };
}

try {
  sentiment = JSON.parse(sentimentRaw.choices?.[0]?.message?.content || '{}');
} catch (error) {
  sentiment = { sentiment: 'neutral', reason: 'sentiment_parse_failed' };
}

return [{
  json: {
    ...base,
    category: classifier.category || 'general',
    urgency: classifier.urgency || 'medium',
    classifier_reason: classifier.reason || '',
    sentiment: sentiment.sentiment || 'neutral',
    sentiment_reason: sentiment.reason || ''
  }
}];

