const base = $('Retrieve Support Knowledge').first().json;
const ragRaw = $('Grounded FAQ Responder').first().json;

let rag = {};
try {
  rag = JSON.parse(ragRaw.choices?.[0]?.message?.content || '{}');
} catch (error) {
  rag = { matched: false, faq_id: '', answer: '', confidence: 'low', rationale: 'rag_parse_failed' };
}

const matched_faq = Boolean(rag.matched) && Boolean(rag.answer);

return [{
  json: {
    ...base,
    matched_faq,
    faq_answer: matched_faq ? rag.answer : '',
    faq_id: matched_faq ? (rag.faq_id || '') : '',
    faq_confidence: rag.confidence || 'low',
    faq_rationale: rag.rationale || ''
  }
}];

const item = $input.first().json;
const query = (item.customer_query || '').toLowerCase();
const negativeSignals = ['angry', 'frustrated', 'refund', 'complaint', 'charged twice', 'urgent', 'not working', 'terrible', 'bad service', 'cancel immediately', 'money deducted', 'scammed', 'fraud'];
const hasNegativeSignal = negativeSignals.some((word) => query.includes(word));

const escalate = (
  item.matched_faq === false ||
  item.urgency === 'high' ||
  item.sentiment === 'negative' ||
  hasNegativeSignal
);

let summary = `Customer query: ${item.customer_query}. Category: ${item.category}. Urgency: ${item.urgency}. Sentiment: ${item.sentiment}.`;
if (!item.matched_faq) summary += ' No grounded answer found from retrieved knowledge.';

return [{
  json: {
    ...item,
    escalate,
    escalation_reason: escalate
      ? 'Complex, urgent, negative, or unsupported query requiring human review'
      : 'Retrieved support knowledge provided a safe grounded answer',
    summary_for_human: summary
  }
}];

const item = $input.first().json;
const ticketId = 'TICK-' + Date.now();
return [{
  json: {
    ...item,
    final_status: 'escalated_to_human',
    escalated: true,
    ticket_id: ticketId,
    response_text: `Your request has been escalated to a human support agent. Ticket ID: ${ticketId}. Our team will review it shortly.`
  }
}];
